import{_ as a,o as s,c as i,ai as n}from"./chunks/framework.C4ntERNc.js";const m=JSON.parse('{"title":"Compile-time Assertions (@check)","description":"","frontmatter":{"title":"Compile-time Assertions (@check)","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/formal-reference/compile-time-check.md","filePath":"reference-manual/formal-reference/compile-time-check.md"}'),o={name:"reference-manual/formal-reference/compile-time-check.md"};function l(t,e,r,c,p,d){return s(),i("div",null,[...e[0]||(e[0]=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/formal-reference/compile-time-check.md for this page in Markdown format</div><h1 id="compile-time-assertions-check" tabindex="-1">Compile-time Assertions (@check) <a class="header-anchor" href="#compile-time-assertions-check" aria-label="Permalink to “Compile-time Assertions (@check)”">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to “Purpose”">​</a></h2><p>Validate compile-time constraints (widths, config sanity, address ranges, parameter compatibility) during elaboration. A <code>@check</code> failure aborts compilation. <code>@check</code> never generates hardware, simulation logic, or runtime behavior.</p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to “Syntax”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@check (&lt;constant_expression&gt;, &lt;string_message&gt;);</span></span></code></pre></div><p>Parentheses are required.</p><h2 id="semantics" tabindex="-1">Semantics <a class="header-anchor" href="#semantics" aria-label="Permalink to “Semantics”">​</a></h2><ul><li>If the expression is <strong>true</strong> (nonzero integer): compilation continues.</li><li>If the expression is <strong>false</strong> (zero): compile error with message &quot;CHECK FAILED: message&quot;.</li><li>If the expression cannot be evaluated as a constant: compile error (non-constant expression).</li></ul><h2 id="placement-rules" tabindex="-1">Placement rules <a class="header-anchor" href="#placement-rules" aria-label="Permalink to “Placement rules”">​</a></h2><p><code>@check</code> may appear in:</p><ul><li>Inside <code>@project</code></li><li>Inside <code>@module</code></li></ul><p><code>@check</code> may <strong>not</strong> appear inside:</p><ul><li>Blocks (ASYNCHRONOUS, SYNCHRONOUS, PORT, WIRE, REGISTER, MEM, etc.)</li><li>Other directives</li></ul><h2 id="expression-rules" tabindex="-1">Expression rules <a class="header-anchor" href="#expression-rules" aria-label="Permalink to “Expression rules”">​</a></h2><p>The expression must evaluate to a constant, nonnegative integer at compile time.</p><p><strong>Allowed operands:</strong></p><ul><li>Integer literals</li><li><code>CONST</code> identifiers</li><li><code>CONFIG.NAME</code> identifiers</li><li>Compile-time integer operators</li><li><code>clog2()</code></li><li>Parentheses</li><li>Comparisons (<code>==</code>, <code>!=</code>, <code>&lt;</code>, <code>&lt;=</code>, <code>&gt;</code>, <code>&gt;=</code>)</li><li>Logical operators (<code>&amp;&amp;</code>, <code>||</code>, <code>!</code>)</li></ul><p><strong>Forbidden operands:</strong></p><ul><li>Module ports, wires, registers</li><li>Memory ports</li><li>Signal slices</li><li>Any runtime expression</li></ul><h2 id="evaluation-order" tabindex="-1">Evaluation order <a class="header-anchor" href="#evaluation-order" aria-label="Permalink to “Evaluation order”">​</a></h2><p><code>@check</code> is evaluated after:</p><ol><li>Resolution of all preceding <code>CONST</code> definitions</li><li>Resolution of all preceding <code>CONFIG</code> entries</li><li>OVERRIDE evaluation (if applicable)</li></ol><p><code>@check</code> can reference <code>CONFIG</code> from the same project and <code>CONST</code> from the same module, including values after any OVERRIDE has been applied.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to “Examples”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// Width constraint</span></span>
<span class="line"><span>CONST { WIDTH = 32; }</span></span>
<span class="line"><span>@check (WIDTH % 8 == 0, &quot;Width must be a multiple of 8.&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Project config constraint</span></span>
<span class="line"><span>@check (CONFIG.DATA_WIDTH &gt;= 8, &quot;Data width must be at least 8.&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Address width sanity</span></span>
<span class="line"><span>CONST { DEPTH = 256; ADDR_W = 8; }</span></span>
<span class="line"><span>@check (ADDR_W == clog2(DEPTH), &quot;Address width does not match depth.&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Invalid: runtime signal</span></span>
<span class="line"><span>@check (select == 3, &quot;...&quot;);</span></span>
<span class="line"><span>// ERROR: non-constant expression in @check</span></span></code></pre></div><h2 id="error-conditions" tabindex="-1">Error conditions <a class="header-anchor" href="#error-conditions" aria-label="Permalink to “Error conditions”">​</a></h2><ul><li>Expression evaluates to zero</li><li>Expression contains any runtime signal</li><li>Expression contains undefined identifiers</li><li>Expression produces a non-integer</li><li>Expression uses operators disallowed in constant expressions</li></ul>`,28)])])}const u=a(o,[["render",l]]);export{m as __pageData,u as default};
